from typing import TypedDict
from langgraph.graph import StateGraph, END

class State(TypedDict):
    input: str
    result: str
    step_count: int

# Simplest node: reads state, returns updates
def process(state: State) -> dict:
    return {
        "result": state["input"].upper(),
        "step_count": state["step_count"] + 1,
    }

# Async node — identical contract, just use async def
async def async_process(state: State) -> dict:
    # await external_api(state["input"])
    return {"result": "async result", "step_count": state["step_count"] + 1}

from langgraph.graph import StateGraph, END
from typing import TypedDict, Literal

class State(TypedDict):
    query: str
    answer: str
    needs_retrieval: bool

def classify(state: State) -> dict:
    # Decide whether retrieval is needed
    needs = "?" in state["query"]
    return {"needs_retrieval": needs}

def retrieve_and_answer(state: State) -> dict:
    return {"answer": f"[Retrieved] Answer for: {state['query']}"}

def direct_answer(state: State) -> dict:
    return {"answer": f"[Direct] {state['query']}"}

# Routing function — called after "classify" node
def route(state: State) -> Literal["retrieve", "direct"]:
    return "retrieve" if state["needs_retrieval"] else "direct"

graph = StateGraph(State)
graph.add_node("classify", classify)
graph.add_node("retrieve", retrieve_and_answer)
graph.add_node("direct", direct_answer)

graph.set_entry_point("classify")
graph.add_conditional_edges(
    "classify",       # source node
    route,            # routing function
    {
        "retrieve": "retrieve",   # return value -> next node
        "direct": "direct",
    },
)
graph.add_edge("retrieve", END)
graph.add_edge("direct", END)

app = graph.compile()
print(app.invoke({"query": "What is Python?"})["answer"])   # [Retrieved]
print(app.invoke({"query": "Hello world"})["answer"])        # [Direct]
